	GetBotEntityRuntimeID(context.Context, *game_control.Empty) (*game_control.Uint64Value, error)
	// GetBotPosition 返回机器人当前位置。
	GetBotPosition(context.Context, *game_control.Empty) (*Vec3Value, error)
	// GetBotDimension 返回机器人当前维度。
	GetBotDimension(context.Context, *game_control.Empty) (*game_control.Int32Value, error)
